@contextmanager
def _ctx() -> Generator[tuple[Session, User]]:
    """Open a worker session and resolve the calling user; always close."""
    session = get_session()
    try:
        try:
            user = resolve_current_user(session)
        except McpAuthError as exc:
            raise ToolError(str(exc)) from exc
        yield session, user
    finally:
        session.close()

